            <p className="table-footnote">* Recency = row-order proxy (no date column)</p>
          )}
        </div>

        {/* в•ђв•ђ SECTION 6: AI tools в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ */}
        <div className="ai-section-divider">
